defaultStatus :: Status
defaultStatus = Status
  { statusMessage = ""
  , statusCode = (toEnum 0)
  , statusUnknownFields = []
  }

instance MessageEncode Status where
  buildMessage msg =
    (if msg.statusMessage == T.empty then mempty else archString 18 msg.statusMessage)
    <> (if fromEnum msg.statusCode == 0 then mempty else archVarint 24 (fromIntegral (fromEnum msg.statusCode)))
    <> encodeUnknownFields msg.statusUnknownFields

instance MessageSize Status where
  messageSize msg =
    (if msg.statusMessage == T.empty then 0 else archStringSize msg.statusMessage)
    + (if fromEnum msg.statusCode == 0 then 0 else archVarintSize (fromIntegral (fromEnum msg.statusCode)))
    + unknownFieldsSize msg.statusUnknownFields

instance MessageDecode Status where
  {-# INLINE messageDecoder #-}
  messageDecoder = loop "" (toEnum 0) []
    where
      loop acc_0 acc_1 acc_unknown_ = withTagM
        (pure (Status {statusMessage = acc_0, statusCode = acc_1, statusUnknownFields = reverse acc_unknown_}))
        (\fn wt -> case fn of
          2 -> do
            v <- decodeFieldString
            loop v acc_1 acc_unknown_
          3 -> do
            v <- decodeFieldEnum
            loop acc_0 v acc_unknown_
          _ -> do
            uf <- captureUnknownField fn (toEnum wt)
            loop acc_0 acc_1 (uf : acc_unknown_))

